<script setup lang="ts">
import { ref, reactive } from 'vue'
import { ElMessage } from 'element-plus'

// 追溯类型选项
const traceTypeOptions = [
  { value: 'forward', label: '正向追溯', icon: 'ArrowDown' },
  { value: 'backward', label: '反向追溯', icon: 'ArrowUp' },
  { value: 'full', label: '全链路追溯', icon: 'Connection' }
]

// 搜索表单
const searchForm = reactive({
  batchNo: '',
  traceType: 'full'
})

// 状态
const loading = ref(false)
const showResult = ref(false)

// 当前批次数据
const currentBatch = ref<any>(null)
const upstreamNodes = ref<any[]>([])
const downstreamNodes = ref<any[]>([])
const fifoQueue = ref<any[]>([])

// 历史记录
const historyList = ref([
  {
    batchNo: 'BT20240604001',
    traceType: 'full',
    traceTypeText: '全链路追溯',
    productName: '高性能基胶-A型',
    searchTime: '2024-06-05 09:30:15'
  },
  {
    batchNo: 'BT20240603002',
    traceType: 'forward',
    traceTypeText: '正向追溯',
    productName: '标准粉料-B型',
    searchTime: '2024-06-04 16:45:22'
  },
  {
    batchNo: 'BT20240602001',
    traceType: 'backward',
    traceTypeText: '反向追溯',
    productName: '调色液-红色系',
    searchTime: '2024-06-03 11:20:08'
  }
])

// Mock 数据生成 - 根据追溯类型返回不同数据
const generateMockData = (batchNo: string, traceType: string) => {
  // 基础当前批次信息
  const current = {
    name: '半成品批次',
    batchNo: batchNo,
    quantity: '850kg',
    date: '2024-06-05',
    statusText: '已完成',
    statusType: 'success',
    icon: 'Collection',
    color: '#409EFF',
    productName: '高性能粘合剂-HP001',
    specification: '25kg/桶',
    productionDate: '2024-06-05',
    productionLine: '1号线-粘合机产线',
    operator: '张三',
    qcResult: '合格',
    qcResultType: 'success',
    tankNo: 'T-A1-001',
    tankName: '罐体 A1（液态基胶储罐）',
    materialCode: 'MAT-001-LQ',
    tankInTime: '2024-06-03 08:30:00'
  }

  // 先进先出队列
  const fifo = [
    { batchNo: 'BT20240603001', inTime: '2024-06-03 08:30:00' },
    { batchNo: 'BT20240604002', inTime: '2024-06-04 09:15:00' },
    { batchNo: batchNo, inTime: '2024-06-05 10:00:00' },
    { batchNo: 'BT20240605002', inTime: '2024-06-05 14:20:00' }
  ]

  // 根据追溯类型返回不同的上下游数据
  let upstream: any[] = []
  let downstream: any[] = []

  if (traceType === 'forward') {
    // 正向追溯 - 只显示下游（成品流向）
    upstream = []
    downstream = [
      {
        id: 'down-1',
        name: '成品入库',
        batchNo: 'FINISH-' + batchNo.slice(-8),
        quantity: '1000箱',
        warehouse: 'A1仓库',
        icon: 'Box',
        color: '#409EFF'
      },
      {
        id: 'down-2',
        name: '包装发货',
        batchNo: 'PACK-' + batchNo.slice(-8),
        quantity: '500托',
        warehouse: 'B2仓库',
        icon: 'ShoppingBag',
        color: '#8E44AD'
      },
      {
        id: 'down-3',
        name: '客户签收',
        batchNo: 'CUST-' + batchNo.slice(-8),
        quantity: '1000箱',
        warehouse: '客户仓库',
        icon: 'Avatar',
        color: '#67C23A'
      }
    ]
  } else if (traceType === 'backward') {
    // 反向追溯 - 只显示上游（原材料来源）
    upstream = [
      {
        id: 'up-1',
        name: '基胶原料',
        batchNo: 'BASE-' + batchNo.slice(-8),
        quantity: '500kg',
        supplier: '供应商A',
        icon: 'Watermelon',
        color: '#67C23A'
      },
      {
        id: 'up-2',
        name: '粉料原料',
        batchNo: 'POWDER-' + batchNo.slice(-8),
        quantity: '300kg',
        supplier: '供应商B',
        icon: 'Sugar',
        color: '#E6A23C'
      },
      {
        id: 'up-3',
        name: '调色液',
        batchNo: 'COLOR-' + batchNo.slice(-8),
        quantity: '50L',
        supplier: '供应商C',
        icon: 'Brush',
        color: '#F56C6C'
      },
      {
        id: 'up-4',
        name: '助剂原料',
        batchNo: 'ADD-' + batchNo.slice(-8),
        quantity: '10kg',
        supplier: '供应商D',
        icon: 'Box',
        color: '#909399'
      }
    ]
    downstream = []
  } else {
    // 全链路追溯 - 显示上下游
    upstream = [
      {
        id: 'up-1',
        name: '基胶原料',
        batchNo: 'BASE-' + batchNo.slice(-8),
        quantity: '500kg',
        supplier: '供应商A',
        icon: 'Watermelon',
        color: '#67C23A'
      },
      {
        id: 'up-2',
        name: '粉料原料',
        batchNo: 'POWDER-' + batchNo.slice(-8),
        quantity: '300kg',
        supplier: '供应商B',
        icon: 'Sugar',
        color: '#E6A23C'
      },
      {
        id: 'up-3',
        name: '调色液',
        batchNo: 'COLOR-' + batchNo.slice(-8),
        quantity: '50L',
        supplier: '供应商C',
        icon: 'Brush',
        color: '#F56C6C'
      }
    ]
    downstream = [
      {
        id: 'down-1',
        name: '成品批次',
        batchNo: 'FINISH-' + batchNo.slice(-8),
        quantity: '1000箱',
        warehouse: 'A1仓库',
        icon: 'Box',
        color: '#409EFF'
      },
      {
        id: 'down-2',
        name: '包装箱',
        batchNo: 'PACK-' + batchNo.slice(-8),
        quantity: '500托',
        warehouse: 'B2仓库',
        icon: 'ShoppingBag',
        color: '#8E44AD'
      }
    ]
  }

  return { upstream, downstream, current, fifo }
}

// 有效的批次号列表（模拟数据库）
const validBatchNumbers = [
  'BT20240605001',
  'BT20240605002',
  'BT20240605003',
  'BT20240604001',
  'BT20240604002',
  'BT20240603001',
  'BT20240603002',
  'BT20240602001'
]

// 验证批次号是否存在
const validateBatchNo = (batchNo: string): boolean => {
  return validBatchNumbers.includes(batchNo.trim())
}

// 查询处理
const handleSearch = async () => {
  if (!searchForm.batchNo.trim()) {
    ElMessage.warning('请输入批次号')
    return
  }

  // 验证批次号是否存在
  if (!validateBatchNo(searchForm.batchNo)) {
    ElMessage.error('批次号不存在，请检查输入')
    return
  }

  loading.value = true
  showResult.value = false

  // 模拟API调用延迟
  await new Promise(resolve => setTimeout(resolve, 800))

  const mockData = generateMockData(searchForm.batchNo, searchForm.traceType)
  upstreamNodes.value = mockData.upstream
  downstreamNodes.value = mockData.downstream
  currentBatch.value = mockData.current
  fifoQueue.value = mockData.fifo

  // 添加到历史记录
  const historyItem = {
    batchNo: searchForm.batchNo,
    traceType: searchForm.traceType,
    traceTypeText: traceTypeOptions.find(t => t.value === searchForm.traceType)?.label || '',
    productName: mockData.current.productName,
    searchTime: new Date().toLocaleString('zh-CN')
  }
  historyList.value.unshift(historyItem)

  showResult.value = true
  loading.value = false

  ElMessage.success('查询成功')
}

// 重置处理
const handleReset = () => {
  searchForm.batchNo = ''
  searchForm.traceType = 'full'
  showResult.value = false
}

// 节点点击处理
const handleNodeClick = (node: any) => {
  ElMessage.info(`点击了节点: ${node.name} - ${node.batchNo}`)
}

// 快速查询
const quickSearch = (batchNo: string) => {
  searchForm.batchNo = batchNo
  handleSearch()
}

// 清空历史
const clearHistory = () => {
  historyList.value = []
  ElMessage.success('历史记录已清空')
}
</script>

